package com.cho2hand.marketplace.specification;
import com.cho2hand.marketplace.entity.listing.Listing;import java.math.BigDecimal;import org.springframework.data.jpa.domain.Specification;
public final class ListingSpecifications {private ListingSpecifications(){}public static Specification<Listing> active(Long status){return(root,q,b)->b.and(b.equal(root.get("listingStatusId"),status),b.isNull(root.get("archivedAt")));}public static Specification<Listing> category(Long id){return id==null?null:(root,q,b)->b.equal(root.get("categoryId"),id);}public static Specification<Listing> condition(Long id){return id==null?null:(root,q,b)->b.equal(root.get("conditionId"),id);}public static Specification<Listing> locationIn(java.util.Collection<Long> ids){return ids==null||ids.isEmpty()?null:(root,q,b)->root.get("locationId").in(ids);}public static Specification<Listing> seller(Long id){return id==null?null:(root,q,b)->b.equal(root.get("sellerUserId"),id);}public static Specification<Listing> price(BigDecimal min,BigDecimal max){return(root,q,b)->{var p=b.conjunction();if(min!=null)p=b.and(p,b.greaterThanOrEqualTo(root.get("priceAmount"),min));if(max!=null)p=b.and(p,b.lessThanOrEqualTo(root.get("priceAmount"),max));return p;};}public static Specification<Listing> keyword(String text){return text==null||text.isBlank()?null:(root,q,b)->{var term="%"+text.trim().toLowerCase()+"%";return b.or(b.like(b.lower(root.get("title")),term),b.like(b.lower(root.get("description")),term));};}}
